CREATE OR REPLACE FUNCTION what_quarter_is(date_in date, start_month integer)
RETURNS integer AS
$$
BEGIN
    RETURN ((EXTRACT(MONTH FROM date_in) - start_month + 12) % 12) / 3 + 1;
END;
$$ LANGUAGE plpgsql;

