CREATE OR REPLACE FUNCTION log_player_name_changes() RETURNS trigger AS $BODY$
BEGIN
    IF NEW.player_name <> OLD.player_name THEN
        INSERT INTO player_audits(player_id, old_player_name, changed_on)
        VALUES(OLD.id, OLD.player_name, now());
    END IF;
    RETURN NEW;
END;
$BODY$;

CREATE TRIGGER tr_change_playername
AFTER UPDATE OF player_name ON player
FOR EACH ROW
EXECUTE PROCEDURE log_player_name_changes()

