CREATE OR REPLACE FUNCTION GapFillInternal(state anyelement, v anyelement) RETURNS anyelement AS $$
BEGIN
    IF v IS NOT NULL THEN
        RETURN v;
    ELSE
        RETURN state;
    END IF;
END;
$$ LANGUAGE PLPGSQL;

CREATE AGGREGATE GapFill(anyelement) (SFUNC=GapFillInternal, STYPE=anyelement);

SELECT 
    id, 
    publisher_id, 
    height_cm, 
    weight_kg, 
    GapFill(height_cm) OVER (PARTITION BY publisher_id ORDER BY id) AS height_cm_filled,
    GapFill(weight_kg) OVER (PARTITION BY publisher_id ORDER BY id) AS weight_kg_filled
FROM superhero

