create or replace function setup_vector_store(table_name text) returns void language plpgsql as $$ 
begin 
    execute 'drop function if exists match_strategies(vector, int, jsonb)'; 
    execute format('create table %I ( id bigint primary key generated always as identity, description text, metadata jsonb )', table_name); 
    execute format('create function match_strategies ( query_embedding vector, match_count int default null, filter jsonb default ''{}''::jsonb ) returns table ( id bigint, description text, metadata jsonb, similarity float ) language plpgsql as $func$ 
    begin 
        return query select id, description, metadata, 1 as similarity from %I where metadata @> filter order by %I.embedding <=> query_embedding limit match_count; 
    end; 
    $func$;', table_name, table_name, table_name); 
end; 
$$

DROP FUNCTION IF EXISTS update_school_inventory_after_supply() CASCADE;
CREATE OR REPLACE FUNCTION update_school_inventory_after_supply()
RETURNS TRIGGER
LANGUAGE plpgsql
AS $trigger$
BEGIN
    UPDATE school_inventory
    SET quantity = quantity + NEW.quantity
    WHERE cdscode = NEW.cdscode
      AND supply_name = NEW.supply_name;
    RETURN NEW;
END;
$trigger$;

DROP TRIGGER IF EXISTS trigger_insert_supply ON school_supplies;
CREATE TRIGGER trigger_insert_supply
AFTER INSERT ON school_supplies
FOR EACH ROW
EXECUTE FUNCTION update_school_inventory_after_supply()

