DECLARE @InputString VARCHAR(100) = '1.25,5.34,6.9';
DECLARE @Values TABLE (Value DECIMAL(10,2), Position INT IDENTITY(1,1));

-- Manual split for older versions
DECLARE @StartPos INT = 1, @EndPos INT, @Value VARCHAR(20);

WHILE @StartPos <= LEN(@InputString)
BEGIN
    SET @EndPos = CHARINDEX(',', @InputString, @StartPos);
    IF @EndPos = 0 SET @EndPos = LEN(@InputString) + 1;

    SET @Value = SUBSTRING(@InputString, @StartPos, @EndPos - @StartPos);
    INSERT INTO @Values (Value) VALUES (TRY_CAST(LTRIM(RTRIM(@Value)) AS DECIMAL(10,2)));

    SET @StartPos = @EndPos + 1;
END

CREATE OR REPLACE FUNCTION FIND_TEST_TABLE_COLUMN(
    IN_COLUMN1 TEST_TABLE.COLUMN1%TYPE,
    IN_COLUMN2 TEST_TABLE.COLUMN2%TYPE,
    IN_COLUMN3 TEST_TABLE.COLUMN3%TYPE,
    IN_COLUMN4 TEST_TABLE.COLUMN4%TYPE,
    IN_REQUESTED_COLUMN VARCHAR2
) RETURN VARCHAR2 IS
    RESULT VARCHAR2(255);
BEGIN
    FOR C_REC IN (
        SELECT *
        FROM TEST_TABLE
        WHERE COLUMN1 = IN_COLUMN1
          AND COLUMN2 = IN_COLUMN2
          AND COLUMN3 = IN_COLUMN3
          AND (IN_COLUMN4 IS NULL OR COLUMN4 = IN_COLUMN4)
    ) LOOP
        IF IN_REQUESTED_COLUMN = 'COLUMN1' THEN
            RESULT := C_REC.COLUMN1;
            EXIT;
        ELSIF IN_REQUESTED_COLUMN = 'COLUMN2' THEN
            RESULT := C_REC.COLUMN2;
            EXIT;
        ELSIF IN_REQUESTED_COLUMN = 'COLUMN3' THEN
            RESULT := C_REC.COLUMN3;
            EXIT;
        ELSIF IN_REQUESTED_COLUMN = 'COLUMN4' THEN
            RESULT := C_REC.COLUMN4;
            EXIT;
        END IF;
    END LOOP;
    RETURN RESULT;
END;

